// No code required for Merchant plan.
// Just share the link and get paid.`},developer:{badge:"recv Developer",title:"Payments Infrastructure. Control in Your Hands.",body:"Professional API and Webhooks for full business automation. Direct payouts and zero turnover commissions.",priceLabel:"$29",period:"per month",stats:[{value:"50k",label:"Requests/mo"},{value:"3",label:"Seats"},{value:"3",label:"Workspaces"},{value:"Standard",label:"Support"}],features:[{title:"Webhook Delivery",body:"Queued delivery with automated retries and HMAC signatures."},{title:"Real-time Monitoring",body:"Transaction monitoring updates invoice state as supported networks are observed."},{title:"Unified API v1",body:"A single interface for native TON, USDT on TON, TRON, Base, and BSC."},{title:"Idempotency",body:"Built-in protection against duplicate transactions at the API level."}],flow:[{title:"API Key Provisioning",body:"Generate live_ keys. Manage scopes for secure backend integration."},{title:"Webhook Config",body:"Set up HMAC-SHA256 signed callbacks for instant notifications."},{title:"Automated Processing",body:"Our watchers track transactions 24/7, confirming payments autonomously."}],code:`// Create Invoice via recv API
